"use client";

import React, { useRef, useEffect, type ReactNode } from "react";
import { gsap } from "gsap";
import { ScrollTrigger } from "gsap/ScrollTrigger";                     
import { MotionPathPlugin } from "gsap/MotionPathPlugin";              
import { Flip } from "gsap/Flip";                         
import { Draggable } from "gsap/Draggable";                            
import { CustomEase } from "gsap/CustomEase";                           
import { Observer } from "gsap/Observer";    
import type {
  GsapAnimationConfig,
  RevealStyle,
  TextEffect,
} from "@/features/gsap";
import { getGsapFromVars, getParallaxDefaults } from "@/features/gsap";

gsap.registerPlugin(
  ScrollTrigger,
  MotionPathPlugin,
  Flip,
  Draggable,
  CustomEase,
  Observer,
);

interface GsapAnimationWrapperProps {
  config?: GsapAnimationConfig | undefined;
  children: ReactNode;
  className?: string | undefined;
}

const DEFAULT_STAGGER = 0.12;
const DEFAULT_STAGGER_FROM = "start";
const KEYFRAME_PRESETS: Record<string, gsap.TweenVars> = {
  shake: {
    keyframes: [
      { x: -6 },
      { x: 6 },
      { x: -4 },
      { x: 4 },
      { x: -2 },
      { x: 2 },
      { x: 0 },
    ],
    ease: "none",
  },
  wobble: {
    keyframes: [
      { rotation: -6, x: -6 },
      { rotation: 6, x: 6 },
      { rotation: -3, x: -3 },
      { rotation: 3, x: 3 },
      { rotation: 0, x: 0 },
    ],
    ease: "sine.inOut",
  },
  wiggle: {
    keyframes: [
      { rotation: 2 },
      { rotation: -2 },
      { rotation: 1.5 },
      { rotation: -1.5 },
      { rotation: 0 },
    ],
    ease: "sine.inOut",
  },
};

function getRevealVars(
  style: RevealStyle,
): { from: gsap.TweenVars; to: gsap.TweenVars } | null {
  switch (style) {
    case "clipUp":
      return {
        from: { clipPath: "inset(100% 0% 0% 0%)" },
        to: { clipPath: "inset(0% 0% 0% 0%)" },
      };
    case "clipDown":
      return {
        from: { clipPath: "inset(0% 0% 100% 0%)" },
        to: { clipPath: "inset(0% 0% 0% 0%)" },
      };
    case "clipLeft":
      return {
        from: { clipPath: "inset(0% 100% 0% 0%)" },
        to: { clipPath: "inset(0% 0% 0% 0%)" },
      };
    case "clipRight":
      return {
        from: { clipPath: "inset(0% 0% 0% 100%)" },
        to: { clipPath: "inset(0% 0% 0% 0%)" },
      };
    case "mask":
      return {
        from: { clipPath: "inset(0% 0% 100% 0%)" },
        to: { clipPath: "inset(0% 0% 0% 0%)" },
      };
    default:
      return null;
  }
}

function shuffleArray<T>(items: T[]): T[] {
  const arr = [...items];
  for (let i = arr.length - 1; i > 0; i -= 1) {
    const j = Math.floor(Math.random() * (i + 1));
    [arr[i], arr[j]] = [arr[j]!, arr[i]!];
  }
  return arr;
}

function hashString(value: string): string {
  let hash = 0;
  for (let i = 0; i < value.length; i += 1) {
    hash = (hash << 5) - hash + value.charCodeAt(i);
    hash |= 0;
  }
  return Math.abs(hash).toString(36);
}

function getVelocityValue(
  velocity: number,
  config: GsapAnimationConfig,
): number {
  const strength = config.velocityStrength ?? 0.15;
  const max = config.velocityMax ?? 20;
  const raw = (velocity / 1000) * strength * 100;
  return gsap.utils.clamp(-max, max, raw);
}

function applyVelocityEffect(
  targets: HTMLElement[],
  velocity: number,
  config: GsapAnimationConfig,
): void {
  if (!targets.length) return;
  const effect = config.velocityEffect ?? "none";
  if (effect === "none") return;
  const value = getVelocityValue(velocity, config);
  if (!Number.isFinite(value)) return;
  const vars: gsap.TweenVars = {
    duration: 0.2,
    ease: "power3.out",
    overwrite: "auto",
  };
  if (effect === "scale") {
    vars.scale = 1 + value / 100;
  } else {
    (vars as Record<string, number>)[effect] = value;
  }
  gsap.to(targets, vars);
}

function resetVelocityEffect(
  targets: HTMLElement[],
  config: GsapAnimationConfig,
): void {
  if (!targets.length) return;
  const effect = config.velocityEffect ?? "none";
  if (effect === "none") return;
  const vars: gsap.TweenVars = {
    duration: 0.3,
    ease: "power3.out",
    overwrite: "auto",
  };
  if (effect === "scale") {
    vars.scale = 1;
  } else {
    (vars as Record<string, number>)[effect] = 0;
  }
  gsap.to(targets, vars);
}

function resolveEase(config: GsapAnimationConfig): string | gsap.EaseFunction {
  if (config.easing !== "custom") {
    return config.easing ?? "power2.out";
  }
  const custom = config.customEase?.trim();
  if (!custom) return "power2.out";
  try {
    const name = `cmsEase-${hashString(custom)}`;
    return CustomEase.create(name, custom);
  } catch (error: unknown) {
    console.warn("Invalid custom ease string:", error);
    return "power2.out";
  }
}

function splitTextElement(
  element: HTMLElement,
  mode: TextEffect,
): { targets: HTMLElement[]; cleanup: () => void } | null {
  if (!["splitChars", "splitWords", "splitLines"].includes(mode)) return null;
  const originalHtml = element.innerHTML;
  const originalText = element.textContent ?? "";
  element.innerHTML = "";

  const createSpan = (text: string): HTMLSpanElement => {
    const span = document.createElement("span");
    span.textContent = text;
    span.style.display = "inline-block";
    span.style.whiteSpace = "pre";
    return span;
  };

  if (mode === "splitChars") {
    const chars = Array.from(originalText);
    const spans = chars.map(
      (char: string): HTMLSpanElement => createSpan(char),
    );
    spans.forEach((span: HTMLSpanElement): void => {
      element.appendChild(span);
    });
    return {
      targets: spans,
      cleanup: (): void => {
        element.innerHTML = originalHtml;
      },
    };
  }

  const words = originalText.split(" ");
  const wordSpans: HTMLSpanElement[] = [];
  words.forEach((word: string, idx: number): void => {
    const span = createSpan(word);
    wordSpans.push(span);
    element.appendChild(span);
    if (idx < words.length - 1) {
      element.appendChild(document.createTextNode(" "));
    }
  });

  if (mode === "splitWords") {
    return {
      targets: wordSpans,
      cleanup: (): void => {
        element.innerHTML = originalHtml;
      },
    };
  }

  // splitLines
  const lines: HTMLElement[][] = [];
  let currentTop: number | null = null;
  wordSpans.forEach((span: HTMLSpanElement): void => {
    const top = span.offsetTop;
    if (currentTop === null || Math.abs(top - currentTop) > 2) {
      lines.push([span]);
      currentTop = top;
    } else {
      lines[lines.length - 1]!.push(span);
    }
  });

  element.innerHTML = "";
  const lineSpans: HTMLSpanElement[] = [];
  lines.forEach((lineWords: HTMLElement[], idx: number): void => {
    const lineSpan = document.createElement("span");
    lineSpan.style.display = "block";
    lineSpan.style.whiteSpace = "pre";
    lineWords.forEach((word: HTMLElement, wordIdx: number): void => {
      lineSpan.appendChild(word);
      if (wordIdx < lineWords.length - 1) {
        lineSpan.appendChild(document.createTextNode(" "));
      }
    });
    lineSpans.push(lineSpan);
    element.appendChild(lineSpan);
    if (idx < lines.length - 1) {
      element.appendChild(document.createTextNode("\n"));
    }
  });

  return {
    targets: lineSpans,
    cleanup: (): void => {
      element.innerHTML = originalHtml;
    },
  };
}

function resolveTargets(
  el: HTMLDivElement,
  config: GsapAnimationConfig,
): gsap.DOMTarget {
  const selector = config.selector?.trim();

  if (!selector) {
    if (config.preset === "stagger") {
      const children = Array.from(el.children);
      return children.length ? children : el;
    }
    return el;
  }

  const scopedSelector = selector.startsWith(">")
    ? `:scope ${selector}`
    : selector;
  const selectorFn = gsap.utils.selector(el);

  try {
    const found = selectorFn(scopedSelector);
    if (found.length) return found;
  } catch {
    // Invalid selector; fall back to animating the wrapper element.
  }

  return el;
}

export function GsapAnimationWrapper({
  config,
  children,
  className,
}: GsapAnimationWrapperProps): React.ReactNode {
  const ref = useRef<HTMLDivElement>(null);

  useEffect(() => {
    if (!config || !ref.current) return;

    const hasCoreAnimation = config.preset !== "none";
    const hasParallax =
      config.parallaxPreset !== undefined && config.parallaxPreset !== "none";
    const hasVelocity =
      config.velocityEffect !== undefined && config.velocityEffect !== "none";
    const hasMotionPath = Boolean(
      config.motionPathEnabled && config.motionPathPath,
    );

    if (!hasCoreAnimation && !hasParallax && !hasVelocity && !hasMotionPath)
      return;

    const el = ref.current;
    const cleanupFns: Array<() => void> = [];
    const ctx = gsap.context(() => {
      const fromVars = getGsapFromVars(config.preset);
      const { transformOrigin, transformPerspective, ...tweenFromVars } =
        fromVars as gsap.TweenVars & {
          transformOrigin?: string;
          transformPerspective?: number | string;
        };
      const duration = config.duration ?? 1;
      const delay = config.delay ?? 0;
      const resolvedEase = resolveEase(config);

      // For bounce preset, override easing
      const finalEase =
        config.preset === "bounce" ? "bounce.out" : resolvedEase;
      const targets = resolveTargets(el, config);
      const targetsArray = gsap.utils.toArray<HTMLElement>(targets);
      const revealVars = getRevealVars(config.revealStyle ?? "none");
      const isFadeOut = config.preset === "fadeOut";
      const keyframePreset = KEYFRAME_PRESETS[config.preset];
      const scrollMode = config.scrollMode ?? "none";
      const scrollStart = config.scrollStart ?? "top 85%";
      const scrollEnd = config.scrollEnd ?? "bottom top";
      const isScrubMode =
        scrollMode === "scrub" ||
        scrollMode === "pin" ||
        scrollMode === "story";
      const baseScrollTrigger =
        scrollMode === "none"
          ? config.trigger === "scroll"
            ? {
                trigger: el,
                start: scrollStart,
                toggleActions: "play none none none",
              }
            : undefined
          : scrollMode === "reveal"
            ? {
                trigger: el,
                start: scrollStart,
                toggleActions: "play none none none",
              }
            : {
                trigger: el,
                start: scrollStart,
                end: scrollEnd,
                scrub: config.scrollScrub ?? 0.6,
                pin:
                  scrollMode === "pin" ||
                  scrollMode === "story" ||
                  config.scrollPin ||
                  false,
                anticipatePin: scrollMode === "story" ? 1 : undefined,
              };

      if (transformOrigin || transformPerspective) {
        gsap.set(targets, {
          ...(transformOrigin ? { transformOrigin } : {}),
          ...(transformPerspective ? { transformPerspective } : {}),
        });
      }

      const timelineModeRaw = config.timelineMode ?? "none";
      const effectiveTimelineMode =
        timelineModeRaw === "none" &&
        scrollMode === "story" &&
        targetsArray.length > 1
          ? "sequence"
          : timelineModeRaw;
      const timelineGap = config.timelineGap ?? 0.15;
      const timelineOverlap = config.timelineOverlap ?? 0.2;
      const timelineResponseOffset = config.timelineResponseOffset ?? 0.2;
      const timelineStaggerEach = config.timelineStaggerEach ?? DEFAULT_STAGGER;
      const timelineWaveAmount = config.timelineWaveAmount ?? 0.5;
      const timelineRandomize = config.timelineRandomize ?? false;
      const timelineLoop = config.timelineLoop ?? false;
      const timelineRepeat = config.timelineRepeat ?? -1;
      const timelineYoyo = config.timelineYoyo ?? false;
      const timelineRepeatDelay = config.timelineRepeatDelay ?? 0.2;

      const orderedTargets =
        timelineRandomize && targetsArray.length > 1
          ? shuffleArray(targetsArray)
          : targetsArray;

      const pickAxisVelocity = (
        axis: string,
        vx: number,
        vy: number,
      ): number => {
        if (axis === "x") return vx;
        if (axis === "y") return vy;
        return Math.abs(vx) > Math.abs(vy) ? vx : vy;
      };

      const makeScrollTrigger = (
        withLabels: boolean,
      ): gsap.TweenVars["scrollTrigger"] => {
        if (!baseScrollTrigger) return undefined;
        const triggerConfig = { ...baseScrollTrigger } as Record<
          string,
          unknown
        >;
        if (withLabels && config.scrollSnap) {
          triggerConfig.snap = {
            snapTo: "labelsDirectional",
            duration: config.scrollSnapDuration ?? 0.35,
            ease: "power1.inOut",
          };
        }
        return triggerConfig as gsap.TweenVars["scrollTrigger"];
      };

      const applyTimelineTween = (
        tl: gsap.core.Timeline,
        target: gsap.TweenTarget,
        position: gsap.Position,
      ): void => {
        if (keyframePreset) {
          tl.to(
            target,
            {
              ...keyframePreset,
              duration,
              ease: keyframePreset.ease ?? finalEase,
            },
            position,
          );
          return;
        }

        if (revealVars && !isFadeOut) {
          tl.fromTo(
            target,
            { ...tweenFromVars, ...revealVars.from },
            {
              ...revealVars.to,
              duration,
              ease: finalEase,
            },
            position,
          );
          return;
        }

        if (isFadeOut) {
          tl.to(
            target,
            {
              opacity: 0,
              duration,
              ease: finalEase,
            },
            position,
          );
          return;
        }

        tl.from(
          target,
          {
            ...tweenFromVars,
            duration,
            ease: finalEase,
          },
          position,
        );
      };

      if (hasCoreAnimation) {
        if (effectiveTimelineMode !== "none" && orderedTargets.length > 1) {
          const allowLoop = timelineLoop && !isScrubMode;
          const timelineVars: gsap.TimelineVars = {
            delay,
            repeat: allowLoop ? timelineRepeat : 0,
            yoyo: allowLoop ? timelineYoyo : false,
            repeatDelay: allowLoop ? timelineRepeatDelay : 0,
            defaults: { ease: finalEase },
          };
          const timelineScrollTrigger = makeScrollTrigger(true);
          if (timelineScrollTrigger) {
            timelineVars.scrollTrigger = timelineScrollTrigger;
          }
          const tl: gsap.core.Timeline = gsap.timeline(timelineVars);

          if (
            effectiveTimelineMode === "cascade" ||
            effectiveTimelineMode === "wave" ||
            effectiveTimelineMode === "ripple"
          ) {
            const staggerConfig: gsap.StaggerVars = {
              each: timelineStaggerEach,
              from: effectiveTimelineMode === "cascade" ? "start" : "center",
            };
            if (effectiveTimelineMode === "wave") {
              staggerConfig.ease = "sine.inOut";
              if (timelineWaveAmount > 0) {
                staggerConfig.amount = timelineWaveAmount;
              }
            }

            if (revealVars && !isFadeOut) {
              tl.fromTo(
                orderedTargets,
                { ...tweenFromVars, ...revealVars.from },
                {
                  ...revealVars.to,
                  duration,
                  ease: finalEase,
                  stagger: staggerConfig,
                },
                0,
              );
            } else if (isFadeOut) {
              tl.to(
                orderedTargets,
                {
                  opacity: 0,
                  duration,
                  ease: finalEase,
                  stagger: staggerConfig,
                },
                0,
              );
            } else {
              tl.from(
                orderedTargets,
                {
                  ...tweenFromVars,
                  duration,
                  ease: finalEase,
                  stagger: staggerConfig,
                },
                0,
              );
            }

            orderedTargets.forEach((_: HTMLElement, index: number): void => {
              const labelTime = index * timelineStaggerEach;
              tl.addLabel(`step-${index}`, labelTime);
            });
          } else {
            let cursor = 0;
            orderedTargets.forEach(
              (target: HTMLElement, index: number): void => {
                let position = cursor;
                if (effectiveTimelineMode === "sequence") {
                  position = index * (duration + timelineGap);
                } else if (effectiveTimelineMode === "overlap") {
                  position = cursor;
                  cursor += Math.max(0, duration - timelineOverlap);
                } else if (effectiveTimelineMode === "domino") {
                  position = cursor;
                  cursor += Math.max(0, duration - timelineOverlap);
                } else if (effectiveTimelineMode === "callResponse") {
                  position =
                    index * timelineGap +
                    (index % 2 === 1 ? timelineResponseOffset : 0);
                }

                applyTimelineTween(tl, target, position);
                tl.addLabel(`step-${index}`, position);

                if (effectiveTimelineMode === "sequence") {
                  cursor = position + duration + timelineGap;
                }
              },
            );
          }
        } else {
          const allowLoop = timelineLoop && !isScrubMode;
          const tweenVars: gsap.TweenVars = {
            ...(isFadeOut ? { opacity: 0 } : tweenFromVars),
            duration,
            delay,
            ease: finalEase,
            repeat: allowLoop ? timelineRepeat : 0,
            yoyo: allowLoop ? timelineYoyo : false,
            repeatDelay: allowLoop ? timelineRepeatDelay : 0,
          };

          if (config.preset === "stagger") {
            const staggerEach = config.staggerEach ?? DEFAULT_STAGGER;
            const staggerAmount = config.staggerAmount ?? 0;
            const staggerFrom = config.staggerFrom ?? DEFAULT_STAGGER_FROM;
            tweenVars.stagger =
              staggerAmount > 0
                ? { amount: staggerAmount, from: staggerFrom }
                : { each: staggerEach, from: staggerFrom };
          }

          const scrollTrigger = makeScrollTrigger(false);
          if (keyframePreset) {
            gsap.to(orderedTargets, {
              ...keyframePreset,
              duration,
              delay,
              ease: keyframePreset.ease ?? finalEase,
              ...(scrollTrigger ? { scrollTrigger } : {}),
            });
            return;
          }

          if (revealVars && !isFadeOut) {
            gsap.fromTo(
              orderedTargets,
              { ...tweenFromVars, ...revealVars.from },
              {
                ...revealVars.to,
                duration,
                delay,
                ease: finalEase,
                ...(scrollTrigger ? { scrollTrigger } : {}),
              },
            );
          } else {
            const tweenFn = isFadeOut ? gsap.to : gsap.from;
            tweenFn(orderedTargets, {
              ...tweenVars,
              ...(scrollTrigger ? { scrollTrigger } : {}),
            });
          }
        }
      }

      if (config.velocityEffect && config.velocityEffect !== "none") {
        if (scrollMode !== "none" || config.trigger === "scroll") {
          const velocityTrigger = ScrollTrigger.create({
            trigger: el,
            start: scrollStart,
            end: scrollEnd,
            onUpdate: (self: ScrollTrigger): void => {
              applyVelocityEffect(targetsArray, self.getVelocity(), config);
            },
            onLeave: (): void => resetVelocityEffect(targetsArray, config),
            onLeaveBack: (): void => resetVelocityEffect(targetsArray, config),
            onRefresh: (): void => resetVelocityEffect(targetsArray, config),
          });
          cleanupFns.push(() => velocityTrigger.kill());
        }
      }

      if (config.parallaxPreset && config.parallaxPreset !== "none") {
        const defaults = getParallaxDefaults(config.parallaxPreset);
        const offset = config.parallaxOffset ?? defaults.offset;
        const axis = config.parallaxAxis === "x" ? "x" : "y";
        const scrub = config.parallaxScrub ?? 0.6;
        const start = config.parallaxStart ?? "top bottom";
        const end = config.parallaxEnd ?? "bottom top";
        const scaleBase = defaults.scale ?? 1;
        const reverse = config.parallaxReverse ? -1 : 1;
        const pattern = config.parallaxPattern ?? "uniform";
        const childStep = config.parallaxChildStep ?? 16;
        const layerStrength = config.parallaxLayerStrength ?? 0.35;
        const layerScaleStep = config.parallaxLayerScaleStep ?? 0.015;
        const randomSeed = config.parallaxRandomSeed ?? 7;

        const targetsArray = gsap.utils.toArray<HTMLElement>(targets);
        if (targetsArray.length) {
          const offsetFn = (index: number): number => {
            const signedBase = offset * reverse;
            const signedStep = childStep * (signedBase >= 0 ? 1 : -1);
            switch (pattern) {
              case "alternate":
                return signedBase * (index % 2 === 0 ? 1 : -1);
              case "increment":
                return signedBase + index * signedStep;
              case "layers":
                return signedBase * (1 + index * layerStrength);
              case "random": {
                const seed =
                  Math.sin(randomSeed * 999 + index * 78.233) * 43758.5453;
                const rand = seed - Math.floor(seed);
                const multiplier = 0.6 + rand * 0.8;
                return signedBase * multiplier;
              }
              default:
                return signedBase;
            }
          };

          const scaleFn = (index: number): number => {
            if (pattern === "layers") {
              return scaleBase + index * layerScaleStep;
            }
            return scaleBase;
          };

          const baseScale = scaleFn(0);
          const hasScale = baseScale !== 1 || pattern === "layers";
          const hasOffset = offsetFn(0) !== 0 || pattern !== "uniform";

          if (hasOffset || hasScale) {
            gsap.to(targetsArray, {
              [axis]: (i: number): number => offsetFn(i),
              ...(hasScale ? { scale: (i: number): number => scaleFn(i) } : {}),
              ease: "none",
              scrollTrigger: {
                trigger: el,
                start,
                end,
                scrub,
              },
            });
          }
        }
      }

      // Motion path
      if (config.motionPathEnabled && config.motionPathPath) {
        const path = config.motionPathPath.trim();
        if (path) {
          const baseStart = config.motionPathStart ?? 0;
          const baseEnd = config.motionPathEnd ?? 1;
          const motionPathBase: MotionPath.Vars = {
            path,
            autoRotate: config.motionPathAutoRotate
              ? (config.motionPathRotateOffset ?? 0)
              : false,
            start: baseStart,
            end: baseEnd,
            ...(config.motionPathAlign ? { align: path } : {}),
          };

          const scrollTrigger = makeScrollTrigger(false);
          const follow = config.motionPathFollow ?? false;
          const spacing = config.motionPathSpacing ?? 0.08;

          if (follow && targetsArray.length > 1) {
            const motionPathVars: MotionPath.Vars = {
              ...motionPathBase,
              start: (index: number): number => baseStart + index * spacing,
              end: (index: number): number => baseEnd + index * spacing,
            };

            gsap.to(targetsArray, {
              motionPath: motionPathVars,
              duration,
              ease: finalEase,
              ...(scrollTrigger ? { scrollTrigger } : {}),
            });
          } else {
            gsap.to(targetsArray, {
              motionPath: motionPathBase,
              duration,
              ease: finalEase,
              ...(scrollTrigger ? { scrollTrigger } : {}),
            });
          }
        }
      }

      // SVG draw
      if (config.svgDrawEnabled) {
        const selector = config.svgDrawSelector?.trim();
        const svgTargets = selector
          ? el.querySelectorAll<SVGGeometryElement>(selector)
          : el.querySelectorAll<SVGGeometryElement>(
              "path, line, circle, rect, polyline, polygon",
            );
        const fromPercent = config.svgDrawFrom ?? 0;
        const toPercent = config.svgDrawTo ?? 100;
        const scrollTrigger = makeScrollTrigger(false);

        svgTargets.forEach((shape: SVGGeometryElement): void => {
          if (!("getTotalLength" in shape)) return;
          const length = shape.getTotalLength();
          const fromOffset = length * (1 - fromPercent / 100);
          const toOffset = length * (1 - toPercent / 100);

          gsap.set(shape, {
            strokeDasharray: length,
            strokeDashoffset: fromOffset,
          });

          gsap.to(shape, {
            strokeDashoffset: toOffset,
            duration,
            ease: finalEase,
            ...(scrollTrigger ? { scrollTrigger } : {}),
          });
        });
      }

      // SVG morph (basic attr tween)
      if (config.svgMorphEnabled && config.svgMorphTo) {
        const selector = config.svgMorphSelector?.trim() || "path";
        const svgTargets = el.querySelectorAll<SVGPathElement>(selector);
        let morphPath = config.svgMorphTo.trim();
        if (
          morphPath &&
          (morphPath.startsWith("#") || morphPath.startsWith("."))
        ) {
          const refPath = document.querySelector<SVGPathElement>(morphPath);
          if (refPath?.getAttribute("d")) {
            morphPath = refPath.getAttribute("d") ?? morphPath;
          }
        }
        if (morphPath) {
          const scrollTrigger = makeScrollTrigger(false);
          svgTargets.forEach((shape: SVGPathElement): void => {
            gsap.to(shape, {
              attr: { d: morphPath },
              duration,
              ease: finalEase,
              ...(scrollTrigger ? { scrollTrigger } : {}),
            });
          });
        }
      }

      // Text effects
      if (config.textEffect && config.textEffect !== "none") {
        const scrollTrigger = makeScrollTrigger(false);
        const effect = config.textEffect;
        const textTargets = targetsArray.filter(
          (node: HTMLElement): node is HTMLElement =>
            node instanceof HTMLElement,
        );

        textTargets.forEach((target: HTMLElement): void => {
          if (effect === "scramble") {
            const original = target.textContent ?? "";
            const chars =
              config.textScrambleChars ??
              "ABCDEFGHIJKLMNOPQRSTUVWXYZ0123456789";
            const tweenState = { progress: 0 };
            gsap.to(tweenState, {
              progress: 1,
              duration,
              ease: finalEase,
              ...(scrollTrigger ? { scrollTrigger } : {}),
              onUpdate: (): void => {
                const revealCount = Math.floor(
                  tweenState.progress * original.length,
                );
                const scrambled = original
                  .split("")
                  .map((char: string, idx: number): string => {
                    if (idx < revealCount || char === " ") return char;
                    const randomIndex = Math.floor(
                      Math.random() * chars.length,
                    );
                    return chars.charAt(randomIndex) || char;
                  })
                  .join("");
                target.textContent = scrambled;
              },
              onComplete: (): void => {
                target.textContent = original;
              },
            });
            cleanupFns.push(() => {
              target.textContent = original;
            });
            return;
          }

          if (effect === "typing") {
            const original = target.textContent ?? "";
            const speed = config.textTypingSpeed ?? 24;
            const typingDuration = Math.max(0.2, original.length / speed);
            target.textContent = "";
            let cursorEl: HTMLSpanElement | null = null;
            if (config.textCursor) {
              cursorEl = document.createElement("span");
              cursorEl.textContent = "|";
              cursorEl.style.marginLeft = "2px";
              cursorEl.style.display = "inline-block";
              target.appendChild(cursorEl);
              gsap.to(cursorEl, {
                opacity: 0.2,
                repeat: -1,
                yoyo: true,
                duration: 0.4,
              });
            }

            const tweenState = { progress: 0 };
            gsap.to(tweenState, {
              progress: 1,
              duration: typingDuration,
              ease: "none",
              ...(scrollTrigger ? { scrollTrigger } : {}),
              onUpdate: () => {
                const count = Math.floor(tweenState.progress * original.length);
                const text = original.slice(0, count);
                if (cursorEl) {
                  cursorEl.remove();
                  target.textContent = text;
                  target.appendChild(cursorEl);
                } else {
                  target.textContent = text;
                }
              },
              onComplete: () => {
                target.textContent = original;
              },
            });
            cleanupFns.push(() => {
              target.textContent = original;
            });
            return;
          }

          if (effect === "countUp") {
            const raw = target.textContent ?? "";
            const parsed = Number.parseFloat(raw.replace(/[^0-9.-]/g, ""));
            const fromValue =
              config.textCountFrom ?? (Number.isNaN(parsed) ? 0 : parsed);
            const toValue =
              config.textCountTo ?? (Number.isNaN(parsed) ? 100 : parsed);
            const decimals = config.textCountDecimals ?? 0;
            const tweenState = { value: fromValue };

            gsap.to(tweenState, {
              value: toValue,
              duration,
              ease: finalEase,
              ...(scrollTrigger ? { scrollTrigger } : {}),
              onUpdate: () => {
                target.textContent = tweenState.value.toFixed(decimals);
              },
              onComplete: () => {
                target.textContent = toValue.toFixed(decimals);
              },
            });
            cleanupFns.push(() => {
              target.textContent = raw;
            });
            return;
          }

          const splitResult = splitTextElement(target, effect);
          if (!splitResult) return;
          const stagger = config.textStagger ?? 0.05;
          gsap.from(splitResult.targets, {
            ...tweenFromVars,
            duration,
            ease: finalEase,
            stagger,
            ...(scrollTrigger ? { scrollTrigger } : {}),
          });
          cleanupFns.push(splitResult.cleanup);
        });
      }

      // Visual effects (filters, clip-path, radius, shadow, background)
      const hasVisualEffect =
        Boolean(config.visualFilterFrom || config.visualFilterTo) ||
        Boolean(config.visualClipFrom || config.visualClipTo) ||
        Boolean(config.visualRadiusFrom || config.visualRadiusTo) ||
        Boolean(config.visualShadowFrom || config.visualShadowTo) ||
        Boolean(config.visualBackgroundFrom || config.visualBackgroundTo);

      if (hasVisualEffect) {
        const scrollTrigger = makeScrollTrigger(false);
        const fromVars: gsap.TweenVars = {};
        const toVars: gsap.TweenVars = {};

        if (config.visualFilterFrom) fromVars.filter = config.visualFilterFrom;
        if (config.visualFilterTo) toVars.filter = config.visualFilterTo;
        if (config.visualClipFrom) fromVars.clipPath = config.visualClipFrom;
        if (config.visualClipTo) toVars.clipPath = config.visualClipTo;
        if (config.visualRadiusFrom)
          fromVars.borderRadius = config.visualRadiusFrom;
        if (config.visualRadiusTo) toVars.borderRadius = config.visualRadiusTo;
        if (config.visualShadowFrom)
          fromVars.boxShadow = config.visualShadowFrom;
        if (config.visualShadowTo) toVars.boxShadow = config.visualShadowTo;
        if (config.visualBackgroundFrom)
          fromVars.background = config.visualBackgroundFrom;
        if (config.visualBackgroundTo)
          toVars.background = config.visualBackgroundTo;

        if (Object.keys(fromVars).length && Object.keys(toVars).length) {
          gsap.fromTo(
            targetsArray,
            { ...fromVars },
            {
              ...toVars,
              duration,
              ease: finalEase,
              ...(scrollTrigger ? { scrollTrigger } : {}),
            },
          );
        } else if (Object.keys(toVars).length) {
          gsap.to(targetsArray, {
            ...toVars,
            duration,
            ease: finalEase,
            ...(scrollTrigger ? { scrollTrigger } : {}),
          });
        } else if (Object.keys(fromVars).length) {
          gsap.from(targetsArray, {
            ...fromVars,
            duration,
            ease: finalEase,
            ...(scrollTrigger ? { scrollTrigger } : {}),
          });
        }
      }

      // Flip layout transitions (basic, mutation-driven)
      if (config.flipEnabled) {
        const selector = config.flipSelector?.trim();
        const flipTargets = selector
          ? Array.from(el.querySelectorAll(selector))
          : Array.from(el.children);
        if (flipTargets.length) {
          let state = Flip.getState(flipTargets);
          const observer = new MutationObserver(() => {
            Flip.from(state, {
              duration,
              ease: finalEase,
              absolute: true,
              scale: config.flipScale ?? true,
              fade: config.flipFade ?? true,
            });
            state = Flip.getState(flipTargets);
          });
          observer.observe(el, {
            childList: true,
            subtree: true,
            attributes: true,
            characterData: true,
          });
          cleanupFns.push(() => observer.disconnect());
        }
      }

      // Draggable interactions
      if (config.draggableEnabled) {
        const velocityMap = new WeakMap<
          Draggable,
          { x: number; y: number; t: number; vx: number; vy: number }
        >();
        const useCarousel = config.draggableCarousel ?? false;
        const dragAxis = config.draggableType ?? "x,y";
        let dragTargets: HTMLElement[] = targetsArray;
        let dragType: Draggable.Vars["type"] = dragAxis;
        let bounds: Draggable.Vars["bounds"];
        let snap: Draggable.Vars["snap"];

        if (useCarousel) {
          const trackSelector = config.draggableCarouselSelector?.trim();
          const track = trackSelector
            ? el.querySelector<HTMLElement>(trackSelector)
            : el;
          if (track) {
            dragTargets = [track];
            dragType = dragAxis === "y" ? "y" : "x";
            const items = Array.from(track.children) as HTMLElement[];
            if (items.length) {
              const positions = items.map((item: HTMLElement): number =>
                dragType === "y" ? -item.offsetTop : -item.offsetLeft,
              );
              const firstPosition = positions[0];
              if (firstPosition !== undefined) {
                const min = Math.min(...positions);
                const max = Math.max(...positions);
                bounds =
                  dragType === "y"
                    ? { minY: min, maxY: max }
                    : { minX: min, maxX: max };
                if (config.draggableCarouselSnap ?? true) {
                  const snapFn = (value: number): number => {
                    let closest = firstPosition;
                    let diff = Math.abs(value - closest);
                    for (let i = 1; i < positions.length; i += 1) {
                      const position = positions[i];
                      if (position === undefined) continue;
                      const d = Math.abs(value - position);
                      if (d < diff) {
                        diff = d;
                        closest = position;
                      }
                    }
                    return closest;
                  };
                  snap = dragType === "y" ? { y: snapFn } : { x: snapFn };
                }
              }
            }
          }
        } else {
          const boundsSelector = config.draggableBounds?.trim();
          bounds = boundsSelector
            ? (document.querySelector(boundsSelector) ?? undefined)
            : undefined;
          if (config.draggableSnap && config.draggableSnap > 0) {
            snap = {
              x: (value: number): number =>
                Math.round(value / config.draggableSnap!) *
                config.draggableSnap!,
              y: (value: number): number =>
                Math.round(value / config.draggableSnap!) *
                config.draggableSnap!,
            };
          }
        }

        if (dragTargets.length) {
          const draggableInstances: Draggable[] = Draggable.create(dragTargets, {
            type: dragType,
            bounds: bounds ?? undefined,
            inertia: false,
            onPress: function (this: Draggable): void {
              const now = performance.now();
              velocityMap.set(this, {
                x: this.x,
                y: this.y,
                t: now,
                vx: 0,
                vy: 0,
              });
            },
            onDrag: function (this: Draggable): void {
              const now = performance.now();
              const state = velocityMap.get(this);
              if (!state) return;
              const dt = now - state.t;
              if (dt > 0) {
                state.vx = ((this.x - state.x) / dt) * 1000;
                state.vy = ((this.y - state.y) / dt) * 1000;
                state.x = this.x;
                state.y = this.y;
                state.t = now;
              }
              const axisVelocity = pickAxisVelocity(
                dragAxis,
                state.vx,
                state.vy,
              );
              applyVelocityEffect(targetsArray, axisVelocity, config);
            },
            onDragEnd: function (this: Draggable): void {
              if (config.draggableMomentum) {
                const state = velocityMap.get(this);
                const vx = state?.vx ?? 0;
                const vy = state?.vy ?? 0;
                const factor = config.draggableMomentumFactor ?? 0.6;
                gsap.to(this.target, {
                  x: `+=${vx * factor}`,
                  y: `+=${vy * factor}`,
                  duration: 0.6,
                  ease: "power3.out",
                });
              }
              resetVelocityEffect(targetsArray, config);
            },
            snap,
          });
          cleanupFns.push((): void => {
            draggableInstances.forEach((instance: Draggable) => instance.kill());
          });
        }
      }

      // Observer-driven gestures
      if (config.observerEnabled) {
        const type = config.observerType ?? "wheel,touch";
        const axis = config.observerAxis ?? "y";
        const speed = config.observerSpeed ?? 1;
        const observerTarget = el;
        const observer = Observer.create({
          target: observerTarget,
          type,
          preventDefault: false,
          onChange: (self: Observer): void => {
            const dx = axis === "y" ? 0 : self.deltaX * speed;
            const dy = axis === "x" ? 0 : self.deltaY * speed;
            if (dx !== 0 || dy !== 0) {
              gsap.to(targetsArray, {
                x: `+=${dx}`,
                y: `+=${dy}`,
                duration: 0.2,
                ease: "power2.out",
                overwrite: "auto",
              });
            }
            const velocity = pickAxisVelocity(
              axis,
              self.velocityX,
              self.velocityY,
            );
            applyVelocityEffect(targetsArray, velocity, config);
          },
          onStop: (): void => {
            resetVelocityEffect(targetsArray, config);
          },
        });
        cleanupFns.push(() => observer.kill());
      }

      // Magnet effect
      if (config.magnetEnabled) {
        const axis = config.magnetAxis ?? "x,y";
        const strength = config.magnetStrength ?? 0.35;
        const radius = config.magnetRadius ?? 140;
        const returnDuration = config.magnetReturn ?? 0.35;
        let frame: number | null = null;
        let pointer = { x: 0, y: 0 };

        const update = (): void => {
          frame = null;
          targetsArray.forEach((target: HTMLElement): void => {
            const rect = target.getBoundingClientRect();
            const cx = rect.left + rect.width / 2;
            const cy = rect.top + rect.height / 2;
            const dx = pointer.x - cx;
            const dy = pointer.y - cy;
            const dist = Math.hypot(dx, dy);
            if (dist < radius) {
              const power = (1 - dist / radius) * strength;
              const x = axis === "y" ? 0 : dx * power;
              const y = axis === "x" ? 0 : dy * power;
              gsap.to(target, {
                x,
                y,
                duration: 0.2,
                ease: "power3.out",
                overwrite: "auto",
              });
            } else {
              gsap.to(target, {
                x: 0,
                y: 0,
                duration: returnDuration,
                ease: "power3.out",
                overwrite: "auto",
              });
            }
          });
        };

        const handleMove = (event: PointerEvent): void => {
          pointer = { x: event.clientX, y: event.clientY };
          if (frame === null) {
            frame = requestAnimationFrame(update);
          }
        };

        const handleLeave = (): void => {
          targetsArray.forEach((target: HTMLElement): void => {
            gsap.to(target, {
              x: 0,
              y: 0,
              duration: returnDuration,
              ease: "power3.out",
              overwrite: "auto",
            });
          });
        };

        el.addEventListener("pointermove", handleMove);
        el.addEventListener("pointerleave", handleLeave);
        cleanupFns.push(() => {
          if (frame !== null) cancelAnimationFrame(frame);
          el.removeEventListener("pointermove", handleMove);
          el.removeEventListener("pointerleave", handleLeave);
        });
      }
    }, ref);

    return (): void => {
      cleanupFns.forEach((fn: () => void): void => {
        fn();
      });
      ctx.revert();
    };
  }, [config]);
  // If no animation configured, render children directly without a wrapper div
  if (!config || config.preset === "none") {
    return <>{children}</>;
  }

  return (
    <div ref={ref} className={className}>
      {children}
    </div>
  );
}

"use client";

import { useState, useMemo, useCallback } from "react";
import { useProductsWithCount } from "@/features/products/hooks/useProductsQuery";

interface UseProductDataWithQueryProps {
  initialCatalogFilter?: string;
  initialPageSize?: number;
  preferencesLoaded?: boolean;
}

/* eslint-disable @typescript-eslint/explicit-function-return-type, @typescript-eslint/explicit-module-boundary-types */
export function useProductDataWithQuery({
  initialCatalogFilter = "all",
  initialPageSize = 24,
  preferencesLoaded = true,
}: UseProductDataWithQueryProps = {}) {
  // Filter state
  const [search, setSearch] = useState<string>("");
  const [debouncedSearch, setDebouncedSearch] = useState<string>("");
  const [sku, setSku] = useState<string>("");
  const [debouncedSku, setDebouncedSku] = useState<string>("");
  const [minPrice, setMinPrice] = useState<number | undefined>(undefined);
  const [maxPrice, setMaxPrice] = useState<number | undefined>(undefined);
  const [startDate, setStartDate] = useState<string>("");
  const [endDate, setEndDate] = useState<string>("");
  const [catalogFilter, setCatalogFilter] = useState(initialCatalogFilter);

  // Pagination state
  const [page, setPage] = useState(1);
  const [pageSize, setPageSize] = useState(initialPageSize);

  // Debounce search
  useState(() => {
    const timer = setTimeout(() => {
      setDebouncedSearch(search);
      setPage(1);
    }, 300);
    return () => clearTimeout(timer);
  });

  // Debounce SKU
  useState(() => {
    const timer = setTimeout(() => {
      setDebouncedSku(sku);
      setPage(1);
    }, 300);
    return () => clearTimeout(timer);
  });

  const filters = useMemo(
    () => ({
      search: debouncedSearch,
      sku: debouncedSku,
      minPrice,
      maxPrice,
      startDate,
      endDate,
      page,
      pageSize,
      catalogId: catalogFilter === "all" ? undefined : catalogFilter,
    }),
    [
      debouncedSearch,
      debouncedSku,
      minPrice,
      maxPrice,
      startDate,
      endDate,
      page,
      pageSize,
      catalogFilter,
    ],
  );

  const { products, total, isLoading, isFetching, error, refetch } =
    useProductsWithCount(filters, {
      enabled: preferencesLoaded,
    });

  const totalPages = useMemo(() => {
    return Math.max(1, Math.ceil(total / pageSize));
  }, [total, pageSize]);

  const resetFilters = useCallback(() => {
    setSearch("");
    setDebouncedSearch("");
    setSku("");
    setDebouncedSku("");
    setMinPrice(undefined);
    setMaxPrice(undefined);
    setStartDate("");
    setEndDate("");
    setPage(1);
  }, []);

  return {
    data: products,
    total,
    totalPages,
    page,
    setPage,
    pageSize,
    setPageSize,
    search,
    setSearch,
    sku,
    setSku,
    minPrice,
    setMinPrice,
    maxPrice,
    setMaxPrice,
    startDate,
    setStartDate,
    endDate,
    setEndDate,
    catalogFilter,
    setCatalogFilter,
    isLoading,
    isFetching,
    error: error
      ? error instanceof Error
        ? error.message
        : "Failed to load products"
      : null,
    refetch,
    resetFilters,
  };
}

"use client";

/* eslint-disable @typescript-eslint/explicit-function-return-type, @typescript-eslint/explicit-module-boundary-types */
import { useMutation, useQueryClient } from "@tanstack/react-query";
import type { ProductWithImages } from "@/features/products/types";
import type { DeleteResponse } from "@/shared/types/api";
import { delay } from "@/shared/utils";

interface UpdateProductPayload {
  id: string;
  data: Partial<ProductWithImages>;
}

export function useCreateProduct() {
  const queryClient = useQueryClient();

  return useMutation({
    onSuccess: async () => {
      // Small delay to ensure DB consistency before refetch
      await delay(500);
      await Promise.all([
        queryClient.invalidateQueries({ queryKey: ["products"] }),
        queryClient.invalidateQueries({ queryKey: ["products-count"] }),
      ]);
    },
  });
}

export function useUpdateProduct() {
  const queryClient = useQueryClient();

  return useMutation({
    mutationFn: async ({ id, data }: UpdateProductPayload) => {
      const response = await fetch(`/api/products/${id}`, {
        method: "PUT",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify(data),
      });
      if (!response.ok) throw new Error("Failed to update product");
      return (await response.json()) as ProductWithImages;
    },
    onSuccess: async () => {
      await Promise.all([
        queryClient.invalidateQueries({ queryKey: ["products"] }),
        queryClient.invalidateQueries({ queryKey: ["products-count"] }),
      ]);
    },
  });
}

export function useDeleteProduct() {
  const queryClient = useQueryClient();

  return useMutation({
    mutationFn: async (id: string) => {
      const response = await fetch(`/api/products/${id}`, {
        method: "DELETE",
      });
      if (!response.ok) throw new Error("Failed to delete product");
      return (await response.json()) as DeleteResponse;
    },
    onSuccess: async () => {
      await Promise.all([
        queryClient.invalidateQueries({ queryKey: ["products"] }),
        queryClient.invalidateQueries({ queryKey: ["products-count"] }),
      ]);
    },
  });
}

"use client";

import { useQuery, useQueries, useQueryClient } from "@tanstack/react-query";
import { getProducts, countProducts } from "@/features/products/api";
import { useCallback } from "react";

interface UseProductsFilters {
  search?: string | undefined;
  sku?: string | undefined;
  minPrice?: number | undefined;
  maxPrice?: number | undefined;
  startDate?: string | undefined;
  endDate?: string | undefined;
  page?: number | undefined;
  pageSize?: number | undefined;
  catalogId?: string | undefined;
  searchLanguage?: string | undefined;
}

interface UseProductsOptions {
  enabled?: boolean;
}

export function useProducts(
  filters: UseProductsFilters,
  options: UseProductsOptions = {},
) {
  const { enabled = true } = options;

  return useQuery({
    queryKey: ["products", filters],
    queryFn: () => getProducts(filters),
    enabled,
  });
}

export function useProductsCount(
  filters: UseProductsFilters,
  options: UseProductsOptions = {},
) {
  const { enabled = true } = options;

  return useQuery({
    queryKey: ["products-count", filters],
    queryFn: () => countProducts(filters),
    enabled,
  });
}

export function useProductsWithCount(
  filters: UseProductsFilters,
  options: UseProductsOptions = {},
) {
  const { enabled = true } = options;
  const queryClient = useQueryClient();

  const results = useQueries({
    queries: [
      {
        queryKey: ["products", filters],
        queryFn: () => getProducts(filters),
        enabled,
      },
      {
        queryKey: ["products-count", filters],
        queryFn: () => countProducts(filters),
        enabled,
      },
    ],
  });

  const [productsQuery, countQuery] = results;

  const refetch = useCallback(async () => {
    await Promise.all([
      queryClient.refetchQueries({ queryKey: ["products"] }),
      queryClient.refetchQueries({ queryKey: ["products-count"] }),
    ]);
  }, [queryClient]);

  return {
    products: productsQuery.data ?? [],
    total: countQuery.data ?? 0,
    isLoading: productsQuery.isPending || countQuery.isPending,
    isFetching: productsQuery.isFetching || countQuery.isFetching,
    error: productsQuery.error || countQuery.error,
    refetch,
  };
}

import "server-only";

import OpenAI from "openai";
import type { ChatCompletionContentPart } from "openai/resources/chat/completions";
import prisma from "@/shared/lib/db/prisma";
import { getMongoDb } from "@/shared/lib/db/mongo-client";
import { getImageFileRepository } from "@/features/files/server";
import type { ProductFormData } from "@/features/products/types";
import type { ImageFileRecord } from "@/shared/types/files";
import fs from "fs/promises";
import path from "path";
import {
  badRequestError,
  configurationError,
  operationFailedError,
} from "@/shared/errors/app-error";

const OLLAMA_BASE_URL = process.env.OLLAMA_BASE_URL || "http://localhost:11434";

// AI-related settings that should be read from MongoDB when available
const AI_SETTINGS_KEYS = new Set([
  "ai_vision_model",
  "ai_vision_user_prompt",
  "ai_vision_prompt",
  "ai_vision_output_enabled",
  "openai_model",
  "openai_api_key",
  "description_generation_user_prompt",
  "description_generation_prompt",
  "ai_generation_output_enabled",
]);

interface MongoSetting {
  _id: string;
  value: string;
}

export async function getSettingValue(key: string): Promise<string | null> {
  let value: string | null = null;

  // For AI settings, prefer MongoDB if available
  if (AI_SETTINGS_KEYS.has(key) && process.env.MONGODB_URI) {
    try {
      const mongo = await getMongoDb();
      const doc = await mongo.collection<MongoSetting>("settings").findOne({ _id: key });
      if (doc && typeof doc.value === "string") {
        value = doc.value;
        return value; // Return immediately if found in MongoDB
      }
    } catch (err) {
      console.warn(`Mongo setting fetch failed for ${key}:`, err);
    }
  }

  // Fall back to Prisma
  if (!value && process.env.DATABASE_URL) {
    try {
      const setting = await prisma.setting.findUnique({
        where: { key },
        select: { value: true },
      });
      if (setting) value = setting.value;
    } catch (err) {
      console.warn(`Prisma setting fetch failed for ${key}:`, err);
    }
  }

  // If still not found and not an AI setting, try MongoDB as fallback
  if (!value && !AI_SETTINGS_KEYS.has(key) && process.env.MONGODB_URI) {
    try {
      const mongo = await getMongoDb();
      const doc = await mongo.collection<MongoSetting>("settings").findOne({ _id: key });
      if (doc && typeof doc.value === "string") {
        value = doc.value;
      }
    } catch (err) {
      console.warn(`Mongo fallback setting fetch failed for ${key}:`, err);
    }
  }

  return value;
}

function getClient(modelName: string, apiKey: string | null): { openai: OpenAI; isOllama: boolean } {
  // Check if it's a real OpenAI model (not gpt-oss or other Ollama variants)
  const modelLower = modelName.toLowerCase();
  const isOpenAI = (modelLower.startsWith("gpt-") && !modelLower.includes("oss")) ||
                   modelLower.startsWith("ft:gpt-") ||
                   modelLower.startsWith("o1-");

  if (isOpenAI) {
    if (!apiKey) {
      throw configurationError("OpenAI API key is missing for GPT model.");
    }
    return { openai: new OpenAI({ apiKey }), isOllama: false };
  }

  // All other models use Ollama
  return {
    openai: new OpenAI({
      baseURL: `${OLLAMA_BASE_URL}/v1`,
      apiKey: "ollama",
    }),
    isOllama: true
  };
}

interface GenerateProductDescriptionResult {
  analysisInitial: string;
  analysisFinal: string;
  descriptionInitial: string;
  descriptionFinal: string;
  description: string;
  analysis: string;
  visionModel: string;
  generationModel: string;
  visionOutputEnabled: boolean;
  generationOutputEnabled: boolean;
}

export async function generateProductDescription(params: {
  productData: ProductFormData;
  imageUrls?: string[] | undefined;
  visionOutputEnabled?: boolean | undefined;
  generationOutputEnabled?: boolean | undefined;
}): Promise<GenerateProductDescriptionResult> {
  const { productData, imageUrls = [], visionOutputEnabled, generationOutputEnabled } = params;

  if (!productData?.name_en) {
    throw badRequestError("Product name is required", { field: "name_en" });
  }

  const [
    apiKeySetting,
    visionModelSetting,
    visionInputPromptSetting,
    visionOutputPromptSetting,
    visionOutputEnabledSetting,
    generationModelSetting,
    generationInputPromptSetting,
    generationOutputPromptSetting,
    generationOutputEnabledSetting,
  ] = await Promise.all([
    getSettingValue("openai_api_key"),
    getSettingValue("ai_vision_model"),
    getSettingValue("ai_vision_user_prompt"),
    getSettingValue("ai_vision_prompt"),
    getSettingValue("ai_vision_output_enabled"),
    getSettingValue("openai_model"),
    getSettingValue("description_generation_user_prompt"),
    getSettingValue("description_generation_prompt"),
    getSettingValue("ai_generation_output_enabled"),
  ]);

  const apiKey = apiKeySetting ?? process.env.OPENAI_API_KEY ?? null;
  const visionModel = visionModelSetting?.trim() || "gemma3:27b";
  const visionInputPrompt = visionInputPromptSetting?.trim() || "Analyze these product images...";
  const visionOutputPrompt = visionOutputPromptSetting?.trim() || "";
  const isVisionOutputEnabled = visionOutputEnabled !== undefined ? visionOutputEnabled : (visionOutputEnabledSetting === "true");

  const generationModel = generationModelSetting?.trim() || "qwen3-vl:30b";
  const generationInputPrompt = generationInputPromptSetting?.trim() || "Generate description for [name_en]";
  const generationOutputPrompt = generationOutputPromptSetting?.trim() || "";
  const isGenerationOutputEnabled = generationOutputEnabled !== undefined ? generationOutputEnabled : (generationOutputEnabledSetting === "true");

  const processPrompt = (text: string, currentResult: string = "", analysisResult: string = "", descriptionInitial: string = ""): { text: string; attachImages: boolean } => {
    let processed = text;
    const hasImagesPlaceholder = processed.includes("[images]");
    processed = processed.replace(/\[analysis\]/g, analysisResult);
    processed = processed.replace(/\[imageAnalysis\]/g, analysisResult);
    processed = processed.replace(/\[description\]/g, descriptionInitial);
    processed = processed.replace(/\[result\]/g, currentResult);
    processed = processed.replace(/\[initialResult\]/g, currentResult);
    processed = processed.replace(/\[images\]/g, "");

    if (productData) {
      for (const key in productData) {
        if (Object.prototype.hasOwnProperty.call(productData, key)) {
          const value = productData[key as keyof ProductFormData];
          if (value !== null && value !== undefined) {
            const stringValue = typeof value === "object" ? JSON.stringify(value) : String(value);
            processed = processed.replace(new RegExp(`\\[${key}\\]`, 'g'), stringValue);
          }
        }
      }
    }
    return { text: processed.trim(), attachImages: hasImagesPlaceholder };
  };

  let processedImages: ChatCompletionContentPart[] = [];
  if (imageUrls.length > 0) {
    const imageFileRepository = await getImageFileRepository();
    const imageFiles = await imageFileRepository.listImageFiles();
    const imageFileMap = new Map(imageFiles.map((file: ImageFileRecord) => [file.filepath, file]));

    const imagePromises = imageUrls.map(async (item: string) => {
      try {
        let base64Image: string;
        let mimetype: string = "image/jpeg";
        if (item.startsWith("http")) {
          const res = await fetch(item);
          if (!res.ok) return null;
          const buffer = Buffer.from(await res.arrayBuffer());
          base64Image = buffer.toString("base64");
          mimetype = res.headers.get("content-type") || "image/jpeg";
        } else {
          const imagePath = path.join(process.cwd(), "public", item);
          const buffer = await fs.readFile(imagePath);
          base64Image = buffer.toString("base64");
          const record = imageFileMap.get(item);
          if (record) mimetype = record.mimetype;
        }
        return { type: "image_url" as const, image_url: { url: `data:${mimetype};base64,${base64Image}` } };
      } catch { return null; }
    });
    processedImages = (await Promise.all(imagePromises)).filter((img): img is ChatCompletionContentPart => img !== null);
  }

  let analysisInitial = "";
  let analysisFinal = "";
  const { openai: visionClient, isOllama: isVisionOllama } = getClient(visionModel, apiKey);

  try {
    const prompt1_1 = processPrompt(visionInputPrompt);
    const content1_1: ChatCompletionContentPart[] = [{ type: "text", text: prompt1_1.text }];
    if (prompt1_1.attachImages) content1_1.push(...processedImages);

    const visionCompletion = await visionClient.chat.completions.create({
      model: visionModel,
      messages: [
        { role: "system", content: "You are an AI assistant." },
        { role: "user", content: content1_1 }
      ],
      max_tokens: 500,
    });
    analysisInitial = visionCompletion.choices[0]?.message.content?.trim() || "";

    if (isVisionOutputEnabled && visionOutputPrompt) {
      const prompt1_2 = processPrompt(visionOutputPrompt, analysisInitial, analysisInitial);
      const content1_2: ChatCompletionContentPart[] = [{ type: "text", text: prompt1_2.text }];
      if (prompt1_2.attachImages) content1_2.push(...processedImages);
      const refineCompletion = await visionClient.chat.completions.create({
        model: visionModel,
        messages: [
          { role: "system", content: "You are an AI assistant." },
          { role: "user", content: content1_2 }
        ],
        max_tokens: 500,
      });
      analysisFinal = refineCompletion.choices[0]?.message.content?.trim() || "";
    }
  } catch (error) {
    const errorMessage = error instanceof Error ? error.message : "Unknown error";
    const isConnectionError = errorMessage.includes("ECONNREFUSED") || 
                             errorMessage.includes("fetch failed") || 
                             errorMessage.includes("failed to fetch");

    if (isVisionOllama && isConnectionError) {
      throw operationFailedError(
        `Description generation failed: Could not connect to Ollama server at ${OLLAMA_BASE_URL}. Please ensure the Ollama server is running and accessible.`,
        undefined,
        { originalError: errorMessage, url: OLLAMA_BASE_URL, model: visionModel }
      );
    }
    throw error;
  }

  const visionResultForNext = analysisFinal || analysisInitial;
  const { openai: generationClient, isOllama: isGenerationOllama } = getClient(generationModel, apiKey);
  let descriptionInitial = "";
  let descriptionFinal = "";

  try {
    const prompt2_1 = processPrompt(generationInputPrompt, visionResultForNext, visionResultForNext);
    const content2_1: ChatCompletionContentPart[] = [{ type: "text", text: prompt2_1.text }];
    if (prompt2_1.attachImages) content2_1.push(...processedImages);
    const genCompletion = await generationClient.chat.completions.create({
      model: generationModel,
      messages: [
        { role: "system", content: "You are a helpful assistant." },
        { role: "user", content: content2_1 }
      ],
      max_tokens: 1000,
    });
    descriptionInitial = genCompletion.choices[0]?.message.content?.trim() || "";

    if (isGenerationOutputEnabled && generationOutputPrompt) {
      const prompt2_2 = processPrompt(generationOutputPrompt, descriptionInitial, visionResultForNext, descriptionInitial);
      const content2_2: ChatCompletionContentPart[] = [{ type: "text", text: prompt2_2.text }];
      if (prompt2_2.attachImages) content2_2.push(...processedImages);
      const refineGenCompletion = await generationClient.chat.completions.create({
        model: generationModel,
        messages: [
          { role: "system", content: "You are a helpful assistant." },
          { role: "user", content: content2_2 }
        ],
        max_tokens: 1000,
      });
      descriptionFinal = refineGenCompletion.choices[0]?.message.content?.trim() || "";
    }
  } catch (error) {
    const errorMessage = error instanceof Error ? error.message : "Unknown error";
    const isConnectionError = errorMessage.includes("ECONNREFUSED") || 
                             errorMessage.includes("fetch failed") || 
                             errorMessage.includes("failed to fetch");

    if (isGenerationOllama && isConnectionError) {
      throw operationFailedError(
        `Description generation failed: Could not connect to Ollama server at ${OLLAMA_BASE_URL}. Please ensure the Ollama server is running and accessible.`,
        undefined,
        { originalError: errorMessage, url: OLLAMA_BASE_URL, model: generationModel }
      );
    }
    throw error;
  }

  return {
    analysisInitial,
    analysisFinal,
    descriptionInitial,
    descriptionFinal,
    description: descriptionFinal || descriptionInitial,
    analysis: analysisFinal || analysisInitial,
    // Include model information for job tracking
    visionModel,
    generationModel,
    visionOutputEnabled: isVisionOutputEnabled,
    generationOutputEnabled: isGenerationOutputEnabled
  };
}

/* eslint-disable @typescript-eslint/explicit-function-return-type, @typescript-eslint/explicit-module-boundary-types, @typescript-eslint/typedef */
import "server-only";

import { ErrorSystem } from "@/features/observability/server";
// This service encapsulates all business logic for managing products.

import fs from "fs/promises";
import path from "path";
import {
  productCreateSchema,
  productUpdateSchema,
} from "@/features/products/validations";
import { getDiskPathFromPublicPath, uploadFile } from "@/features/files/server";
import { getProductRepository } from "@/features/products/services/product-repository";
import type { ProductFilters, ProductRepository } from "@/features/products/types/services/product-repository";
import { getImageFileRepository } from "@/features/files/server";
import type { ImageFileRepository } from "@/features/files/types/services/image-file-repository";
import { getCatalogRepository } from "@/features/products/services/catalog-repository";
import { badRequestError } from "@/shared/errors/app-error";
import type { ProductWithImages, ProductImageRecord, ProductRecord } from "@/features/products/types";

const resolveProductRepository = async (): Promise<ProductRepository> => getProductRepository();
const resolveImageFileRepository = async (): Promise<ImageFileRepository> => getImageFileRepository();

/**
 * Retrieves a list of products based on the provided filters.
 * @param filters - The filter criteria.
 * @returns A list of products.
 */
async function getProducts(filters: ProductFilters): Promise<ProductWithImages[]> {
  const productRepository = await resolveProductRepository();
  const products = await productRepository.getProducts(filters);

  return Promise.all(
    products.map(async (product: ProductWithImages): Promise<ProductWithImages> => {
      if (!product.images?.length) {
        return product;
      }

      const filteredImages = await Promise.all(
        product.images.map(async (image: ProductImageRecord): Promise<ProductImageRecord | null> => {
          const filepath = image.imageFile?.filepath;
          if (!filepath) {
            return null;
          }

          if (/^(https?:|data:)/i.test(filepath)) {
            return image;
          }

          try {
            await fs.access(getDiskPathFromPublicPath(filepath));
            return image;
          } catch {
            return null;
          }
        })
      );

      return {
        ...product,
        images: filteredImages.filter(Boolean),
      };
    })
  );
}

/**
 * Counts the total number of products based on filters.
 * @param filters - The filter criteria.
 * @returns The total count.
 */
async function countProducts(filters: ProductFilters): Promise<number> {
  const productRepository = await resolveProductRepository();
  return productRepository.countProducts(filters);
}

/**
 * Retrieves a single product by its ID.
 * @param id - The ID of the product to retrieve.
 * @returns The product, or null if not found.
 */
async function getProductById(id: string): Promise<ProductWithImages | null> {
  const productRepository = await resolveProductRepository();
  return productRepository.getProductById(id);
}

async function getProductBySku(sku: string): Promise<ProductWithImages | null> {
  const productRepository = await resolveProductRepository();
  const product = await productRepository.getProductBySku(sku);
  if (!product) return null;
  return getProductById(product.id);
}

/**
 * Creates a new product.
 * @param formData - The product data from the form.
 * @returns The newly created product.
 */
async function createProduct(formData: FormData): Promise<ProductWithImages | null> {
  await ErrorSystem.logInfo("Creating product...");
  try {
    const validatedData = productCreateSchema.parse(
      Object.fromEntries(formData.entries())
    );
    await ErrorSystem.logInfo("Validated data", { validatedData });
    const productRepository = await resolveProductRepository();
    const product = await productRepository.createProduct(validatedData);

    const images = formData.getAll("images") as File[];
    const imageFileIds = formData.getAll("imageFileIds") as string[];
    const catalogIds = normalizeCatalogIds(formData.getAll("catalogIds"));
    const categoryIds = normalizeCategoryIds(formData.getAll("categoryIds"));
    const tagIds = normalizeTagIds(formData.getAll("tagIds"));
    await linkImagesToProduct(
      product.id,
      images,
      imageFileIds,
      validatedData.sku
    );
    await updateProductCatalogs(product.id, catalogIds);
    await updateProductCategories(product.id, categoryIds);
    await updateProductTags(product.id, tagIds);

    return await getProductById(product.id);
  } catch (error) {
    await ErrorSystem.captureException(error, {
      service: "productService",
      action: "createProduct",
    });
    throw error;
  }
}

/**
 * Updates an existing product.
 * @param id - The ID of the product to update.
 * @param formData - The updated product data from the form.
 * @returns The updated product, or null if not found.
 */
async function updateProduct(id: string, formData: FormData): Promise<ProductWithImages | null> {
  await ErrorSystem.logInfo(`Updating product ${id}...`);
  try {
    const validatedData = productUpdateSchema.parse(
      Object.fromEntries(formData.entries())
    );
    await ErrorSystem.logInfo("Validated data", { validatedData });
    const productRepository = await resolveProductRepository();
    const updatedProduct = await productRepository.updateProduct(
      id,
      validatedData
    );
    if (!updatedProduct) return null;

    const images = formData.getAll("images") as File[];
    const imageFileIds = formData.getAll("imageFileIds") as string[];
    await linkImagesToProduct(id, images, imageFileIds, validatedData.sku);
    if (validatedData.sku) {
      await moveLinkedTempImagesToSku(id, validatedData.sku);
    }

    // Only update catalogs/categories/tags if explicitly provided in formData
    if (formData.has("catalogIds")) {
      const catalogIds = normalizeCatalogIds(formData.getAll("catalogIds"));
      await updateProductCatalogs(id, catalogIds);
    }
    if (formData.has("categoryIds")) {
      const categoryIds = normalizeCategoryIds(formData.getAll("categoryIds"));
      await updateProductCategories(id, categoryIds);
    }
    if (formData.has("tagIds")) {
      const tagIds = normalizeTagIds(formData.getAll("tagIds"));
      await updateProductTags(id, tagIds);
    }

    return await getProductById(updatedProduct.id);
  } catch (error) {
    await ErrorSystem.captureException(error, {
      service: "productService",
      action: "updateProduct",
      productId: id,
    });
    throw error;
  }
}

/**
 * Deletes a product.
 * @param id - The ID of the product to delete.
 * @returns The deleted product, or null if not found.
 */
async function deleteProduct(id: string): Promise<ProductRecord | null> {
  await ErrorSystem.logInfo(`Deleting product ${id}...`);
  try {
    const productRepository = await resolveProductRepository();
    return await productRepository.deleteProduct(id);
  } catch (error) {
    await ErrorSystem.captureException(error, {
      service: "productService",
      action: "deleteProduct",
      productId: id,
    });
    throw error;
  }
}

/**
 * Duplicates a product without images and with a new SKU.
 * @param id - The ID of the product to duplicate.
 * @param sku - The new SKU for the duplicated product.
 * @returns The duplicated product, or null if not found.
 */
async function duplicateProduct(id: string, sku: string): Promise<ProductWithImages | null> {
  await ErrorSystem.logInfo(`Duplicating product ${id} with new SKU ${sku}...`);
  try {
    const trimmedSku = sku.trim();
    const skuPattern = /^[A-Z0-9]+$/;
    if (!trimmedSku) {
      throw badRequestError("SKU is required", { field: "sku" });
    }
    if (!skuPattern.test(trimmedSku)) {
      throw badRequestError("SKU must use uppercase letters and numbers only", {
        field: "sku",
        value: trimmedSku,
      });
    }

    const productRepository = await resolveProductRepository();
    const duplicatedProduct = await productRepository.duplicateProduct(
      id,
      trimmedSku
    );
    if (!duplicatedProduct) return null;
    return await getProductById(duplicatedProduct.id);
  } catch (error) {
    await ErrorSystem.captureException(error, {
      service: "productService",
      action: "duplicateProduct",
      productId: id,
      newSku: sku,
    });
    throw error;
  }
}

/**
 * Unlinks an image from a product.
 * @param productId - The ID of the product.
 * @param imageFileId - The ID of the image file.
 * @returns The result of the deletion.
 */
// Why: Images may be linked to multiple products. Only delete the physical file
// and folder after confirming no other products reference this image. This prevents
// accidental data loss if the same image is reused and orphaned disk directories
// from cluttering the storage.
async function unlinkImageFromProduct(productId: string, imageFileId: string): Promise<null> {
  const productRepository = await resolveProductRepository();
  const imageFileRepository = await resolveImageFileRepository();
  await productRepository.removeProductImage(productId, imageFileId);
  const remainingLinks =
    await productRepository.countProductsByImageFileId(imageFileId);

  if (remainingLinks === 0) {
    const imageFile = await imageFileRepository.getImageFileById(imageFileId);

    if (imageFile) {
      const isExternal = /^https?:\/\//i.test(imageFile.filepath);
      if (!isExternal) {
        try {
          await fs.unlink(getDiskPathFromPublicPath(imageFile.filepath));
        } catch (error: unknown) {
          if (error instanceof Error && (error as NodeJS.ErrnoException).code !== "ENOENT") {
            throw error;
          }
        }
      }

      await imageFileRepository.deleteImageFile(imageFileId);

      if (!isExternal) {
        const folderDiskPath = path.dirname(
          getDiskPathFromPublicPath(imageFile.filepath)
        );
        if (folderDiskPath.startsWith(path.join(process.cwd(), "public", "uploads", "products"))) {
          try {
            const folderContents = await fs.readdir(folderDiskPath);
            if (folderContents.length === 0) {
              await fs.rmdir(folderDiskPath);
            }
          } catch (error: unknown) {
            if (error instanceof Error && (error as NodeJS.ErrnoException).code !== "ENOENT") {
              throw error;
            }
          }
        }
      }
    }
  }

  return null;
}

/**
 * Links images to a product. This includes uploading new images and linking existing ones.
 * @param productId - The ID of the product.
 * @param images - The new image files to upload.
 * @param imageFileIds - The IDs of the existing image files to link.
 */
async function linkImagesToProduct(
  productId: string,
  images: File[],
  imageFileIds: string[],
  productSku?: string | null
): Promise<void> {
  const productRepository = await resolveProductRepository();
  const allImageFileIds = [...imageFileIds];

  if (images.length > 0) {
    for (const image of images) {
      // Filter out empty file inputs
      if (image.size > 0) {
        const uploadedImage = await uploadFile(image, {
          category: "products",
          sku: productSku,
        });
        allImageFileIds.push(uploadedImage.id);
      }
    }
  }

  if (productSku && imageFileIds.length > 0) {
    await moveTempImageFilesToSku(imageFileIds, productSku);
  }

  if (allImageFileIds.length > 0) {
    await productRepository.addProductImages(productId, allImageFileIds);
  }
}

const tempProductPathPrefix = "/uploads/products/temp/";

// Why: HTML form's getAll("catalogIds") returns entries for EACH selected item.
// Normalize to trim whitespace (user selection artifacts) and filter empty strings
// (unchecked checkboxes). This prevents invalid IDs from entering the database.
function normalizeCatalogIds(entries: FormDataEntryValue[]): string[] {
  return entries
    .map((entry: FormDataEntryValue): string => (typeof entry === "string" ? entry.trim() : ""))
    .filter((entry: string): boolean => entry.length > 0);
}

function normalizeCategoryIds(entries: FormDataEntryValue[]): string[] {
  return entries
    .map((entry: FormDataEntryValue): string => (typeof entry === "string" ? entry.trim() : ""))
    .filter((entry: string): boolean => entry.length > 0);
}

function normalizeTagIds(entries: FormDataEntryValue[]): string[] {
  return entries
    .map((entry: FormDataEntryValue): string => (typeof entry === "string" ? entry.trim() : ""))
    .filter((entry: string): boolean => entry.length > 0);
}

async function updateProductCatalogs(productId: string, catalogIds: string[]): Promise<void> {
  const productRepository = await resolveProductRepository();
  await productRepository.replaceProductCatalogs(productId, catalogIds);

  // Why: Products need a default price group for inventory/listing calculations.
  // Auto-assigning from the first assigned catalog prevents incomplete product state.
  // Only sets it if the product doesn't already have one to preserve manual overrides.
  const firstCatalogId = catalogIds[0];
  if (firstCatalogId) {
    const product = await productRepository.getProductById(productId);
    if (product && !product.defaultPriceGroupId) {
      const catalogRepository = await getCatalogRepository();
      const catalog = await catalogRepository.getCatalogById(firstCatalogId);
      if (catalog?.defaultPriceGroupId) {
        await productRepository.updateProduct(productId, {
          defaultPriceGroupId: catalog.defaultPriceGroupId,
        });
      }
    }
  }
}

async function updateProductCategories(productId: string, categoryIds: string[]): Promise<void> {
  const productRepository = await resolveProductRepository();
  await productRepository.replaceProductCategories(productId, categoryIds);
}

async function updateProductTags(productId: string, tagIds: string[]): Promise<void> {
  const productRepository = await resolveProductRepository();
  await productRepository.replaceProductTags(productId, tagIds);
}

// Why: Temp path allows users to upload images before saving a product. Once a
// SKU is assigned, we permanently organize images by SKU for easy product recovery.
// Sanitization (replacing non-alphanumeric with underscore) prevents path injection
// and filesystem-specific naming issues across different OS environments.
async function moveTempImageFilesToSku(imageFileIds: string[], sku: string): Promise<void> {
  const imageFileRepository = await resolveImageFileRepository();
  const imageFiles = await imageFileRepository.findImageFilesByIds(
    imageFileIds
  );

  for (const imageFile of imageFiles) {
    if (!imageFile.filepath.startsWith(tempProductPathPrefix)) {
      continue;
    }

    const filename = imageFile.filepath.slice(tempProductPathPrefix.length);
    const safeSku = sku.trim().replace(/[^a-zA-Z0-9-_]/g, "_");
    const targetPublicDir = `/uploads/products/${safeSku}`;
    const targetPublicPath = `${targetPublicDir}/${filename}`;

    await fs.mkdir(
      path.join(process.cwd(), "public", "uploads", "products", safeSku),
      { recursive: true }
    );
    await fs.rename(
      getDiskPathFromPublicPath(imageFile.filepath),
      getDiskPathFromPublicPath(targetPublicPath)
    );

    await imageFileRepository.updateImageFilePath(
      imageFile.id,
      targetPublicPath
    );
  }
}

async function moveLinkedTempImagesToSku(productId: string, sku: string): Promise<void> {
  const productRepository = await resolveProductRepository();
  const product = await productRepository.getProductById(productId);
  const imageFileIds =
    product?.images
      .filter((image: ProductImageRecord): boolean =>
        image.imageFile.filepath.startsWith(tempProductPathPrefix)
      )
      .map((image: ProductImageRecord): string => image.imageFileId) ?? [];
  if (imageFileIds.length > 0) {
    await moveTempImageFilesToSku(imageFileIds, sku);
  }
}

